// CAMADA 1: Match exato de regras por produto/país
const lead = $('Webhook').first().json.lead;
const rules = $('Get Active Routing Rules').all().map(r => r.json);
const members = $('Get Active Team Members').all().map(m => m.json);

const product = (lead.primary_solution || '').toLowerCase();
const country = (lead.company_country || '').toLowerCase();

let matchedRule = null;
let matchedMemberIds = [];

for (const rule of rules) {
  const cond = rule.conditions || {};
  const productMatch = !cond.product || cond.product.toLowerCase() === product;
  const countryMatch = !cond.country || cond.country.toLowerCase() === country;
  const territoryMatch = !cond.territories || 
    cond.territories.some(t => t.toLowerCase() === country);

  if (productMatch && (countryMatch || territoryMatch)) {
    // Empty conditions = fallback rule, skip if priority < 50
    if (Object.keys(cond).length === 0 && rule.priority < 50) continue;
    matchedRule = rule;
    matchedMemberIds = rule.assign_to || [];
    break;
  }
}

if (matchedRule && matchedMemberIds.length > 0) {
  const eligibleMembers = members.filter(m => matchedMemberIds.includes(m.id));
  return [{
    json: {
      routing_layer: 'layer_1_rules',
      matched_rule: matchedRule.name,
      eligible_members: eligibleMembers,
      lead,
      use_round_robin: matchedRule.round_robin,
      all_members: members
    }
  }];
}

// No exact match — go to layer 2 (AI)
return [{
  json: {
    routing_layer: 'layer_2_ai',
    matched_rule: null,
    eligible_members: members,
    lead,
    use_round_robin: false,
    all_members: members
  }
}];

