// Round-robin or select from AI response
const input = $('Layer 1 — Rule Matching').first().json;
const lead = input.lead;
let assignedMember;
let reason;

if (input.routing_layer === 'layer_1_rules') {
  // Layer 1: round-robin among eligible members
  const eligible = input.eligible_members;
  const history = $('Get Routing History').all().map(h => h.json);

  if (input.use_round_robin && eligible.length > 1) {
    // Find member with fewest recent assignments
    const counts = {};
    eligible.forEach(m => counts[m.id] = 0);
    history.forEach(h => {
      if (counts[h.assigned_to] !== undefined) counts[h.assigned_to]++;
    });
    const sorted = eligible.sort((a, b) => (counts[a.id] || 0) - (counts[b.id] || 0));
    assignedMember = sorted[0];
    reason = `Round-robin: ${assignedMember.name} tem menos atribuições recentes (regra: ${input.matched_rule})`;
  } else {
    assignedMember = eligible[0];
    reason = `Regra fixa: ${input.matched_rule}`;
  }
} else {
  // Layer 2: parse Claude response
  try {
    const claudeResponse = $('Claude — AI Routing Decision').first().json;
    const parsed = typeof claudeResponse === 'string' ? JSON.parse(claudeResponse) : claudeResponse;
    const aiId = parsed.assigned_to_id;
    assignedMember = input.all_members.find(m => m.id === aiId) || input.all_members[0];
    reason = parsed.reason || 'AI routing';
  } catch (e) {
    // Fallback: first active member
    assignedMember = input.all_members[0];
    reason = 'Fallback: primeiro membro ativo';
  }
}

return [{
  json: {
    assigned_to: assignedMember,
    reason,
    lead,
    routing_layer: input.routing_layer
  }
}];

